class Solution {
    public int maxFreq(String s, int maxLetters, int minSize, int maxSize) {
        int maxFrequency = 0;
        for (int windowSize = minSize; windowSize <= maxSize; windowSize++) {
            Map<String, Integer> frequencyMap = new HashMap<>();
            for (int i = 0; i <= s.length() - windowSize; i++) {
                String substring = s.substring(i, i + windowSize);
                if (getUniqueChars(substring) <= maxLetters) {
                    frequencyMap.put(substring, frequencyMap.getOrDefault(substring, 0) + 1);
                    maxFrequency = Math.max(maxFrequency, frequencyMap.get(substring));
                }
            }
        }
        return maxFrequency;
    }

    private int getUniqueChars(String s) {
        Set<Character> uniqueChars = new HashSet<>();
        for (char c : s.toCharArray()) {
            uniqueChars.add(c);
        }
        return uniqueChars.size();
    }
}
